"""
Temporary script to decode base64 data to PDF/file
"""

import base64

# Paste your base64 encoded data here
encoded_data = """

"""

# Clean up the data (remove whitespace/newlines)
encoded_data = encoded_data.strip()

# Decode
decoded_bytes = base64.b64decode(encoded_data)

# Check if it's text (markdown) or binary (PDF)
try:
    text_content = decoded_bytes.decode('utf-8')
    print("Decoded content is TEXT (Markdown):\n")
    print(text_content)
    
    # Save as markdown file
    with open("output_resume.md", "w", encoding="utf-8") as f:
        f.write(text_content)
    print("\n\nSaved to: output_resume.md")
    
except UnicodeDecodeError:
    # It's binary (likely PDF)
    with open("output_resume.pdf", "wb") as f:
        f.write(decoded_bytes)
    print("Saved to: output_resume.pdf")
